function nameToId(name) {
  return name.toLowerCase()
    .replace(/[äÄ]/g, 'a').replace(/[öÖ]/g, 'o').replace(/[üÜ]/g, 'u')
    .replace(/[éèê]/g, 'e').replace(/[ñ]/g, 'n').replace(/[ó]/g, 'o')
    .replace(/[ą]/g, 'a').replace(/[ó]/g, 'o').replace(/[ě]/g, 'e').replace(/[í]/g, 'i')
    .replace(/\s+/g, '-').replace(/[^a-z0-9\-]/g, '');
}

// ─── RENDER NAV ───────────────────────────────────────────────────────────────

function renderNav(currentPage) {
  const page = document.getElementById('page');
  const filename = currentPage || (window.location.pathname.split('/').pop() || 'index.html');

  document.getElementById('topbar').innerHTML = `
    <a class="topbar-brand" href="index.html">${LOGO_SVG} VORTEXFOODS™ WIKI</a>
    <nav class="topbar-nav">
      ${NAV_LINKS.map(l => `<a href="${l.href}" class="${l.href === filename ? 'active' : ''}">${l.label}</a>`).join('')}
    </nav>`;

  const sb = document.getElementById('sidebar');
  let html = `<div class="sb-search"><input type="text" id="sb-search" placeholder="Search characters…" oninput="sidebarSearch(this.value)"></div>`;

  for (const s of SIDEBAR_SECTIONS) {
    if (s.divider) { html += '<hr class="sb-divider">'; continue; }
    html += `<div class="sb-section"><span class="sb-label">${s.label}</span>`;
    for (const l of s.links) {
      const isActive = l.href === filename || (l.href.includes('#') && l.href.split('#')[0] === filename);
      html += `<a class="sb-link${isActive ? ' active' : ''}" href="${l.href}">${l.label}</a>`;
    }
    html += '</div>';
  }

  sb.innerHTML = html;
}

function sidebarSearch(q) {
  if (!q || q.length < 2) return;
  const term = q.toLowerCase();
  const all = [...germanCharacters, ...americanCharacters, ...guestCharacters, ...shrunkenVictims];
  const match = all.find(c => c.name.toLowerCase().includes(term));
  if (match) window.location = `characters.html#${match.id}`;
}

